	assert(em   != NULL);
	assert(file != NULL);
	fprintf(file, "<%s", em_type_to_cstr(em->type));
	switch (em->type) {
	case EM_PUSH:
		fprintf(file, " ");
		data_fprintf(&em->data, file);
		break;
