		fprintf(file, " %s", em->data.as.int_ == DATA_STDOUT? "stdout" : "stderr");
		break;
	case EM_PRINT_BEGIN: case EM_IF_BEGIN:
		fprintf(file, " ref: %zu", em->ref);
		break;
	default: break;
	}
	fprintf(file, " %s:%zu:%zu>\n", em->path, em->row, em->col);
}
