	assert(prog != NULL);
	assert(prog->ems != NULL);
	free(prog->ems);
}
void program_push(program_t *prog, em_t em) {
	assert(prog != NULL);
	if (prog->size >= prog->cap) {
		prog->cap *= 2;
		prog->ems  = (em_t*)realloc(prog->ems, prog->cap * sizeof(em_t));
		assert(prog->ems != NULL);
	}
	prog->ems[prog->size ++] = em;
