	[EM_LESS] = ":<",
	[EM_EQU]  = ":|",
	[EM_NEQU] = "x|",
	[EM_PRINT_BEGIN] = ":O",
	[EM_PRINT_END]   = NULL,
	[EM_IF_BEGIN] = ":/",
	[EM_IF_END]   = ":\\",
	[EM_LOOP_BEGIN] = ":@",
	[EM_LOOP_END]   = "@:",
	[EM_EXIT] = "X_X",
	[EM_DUP]  = ":D",
	[EM_SWAP] = ":S",
